#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
typedef long long LL;
#define int long long
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
const int N=2e5+10;int S[N],V[N],head[N],des[N<<1],nxt[N<<1],cgt,n,cit,S1;
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
//
int top[N],fa[N],idx[N],mxs[N],siz[N],dep[N];
inline void dfs1(const int &u=1,const int &f=0)
{
	dep[u]=dep[fa[u]=f]+1;siz[u]=1;S[u]=V[u];int mx=0;
	grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];S[u]+=S[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;} 
}
inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
{
	idx[u]=++cit;top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]); 
}
//
int Sm[N<<2],Tg[N<<2],Tm[N],Sq[N<<2];
inline void pushdown(const int &cur,const int &l,const int &r)
{
	const int &mid=(l+r)>>1,&ls=cur<<1,&rs=ls|1,&k=Tg[cur];
	Sq[ls]+=(mid-l+1)*k*k+2*k*Sm[ls]; Sq[rs]+=(r-mid)*k*k+2*k*Sm[rs];
	Tg[ls]+=k;Tg[rs]+=k;Sm[ls]+=(mid-l+1)*k;Sm[rs]+=(r-mid)*k; Tg[cur]=0;
}
inline void update(const int &cur){Sm[cur]=Sm[cur<<1]+Sm[cur<<1|1];Sq[cur]=Sq[cur<<1]+Sq[cur<<1|1];}
inline void add(const int &ql,const int &qr,const int &w,const int &l=1,const int &r=n,const int &cur=1)
{
	if(ql<=l&&r<=qr)
	{
		Sq[cur]+=(r-l+1)*w*w+2*w*Sm[cur];
		Sm[cur]+=(r-l+1)*w;Tg[cur]+=w;return;
	}
	pushdown(cur,l,r);const int &mid=(l+r)>>1;
	if(ql<=mid)add(ql,qr,w,l,mid,cur<<1);if(qr>mid)add(ql,qr,w,mid+1,r,cur<<1|1);update(cur); 
}
inline int qry(const int &ql,const int &qr,const int &l=1,const int &r=n,const int &cur=1)
{
	if(ql<=l&&r<=qr)return Sq[cur];pushdown(cur,l,r);const int &mid=(l+r)>>1;int res=0;
	if(ql<=mid)res=qry(ql,qr,l,mid,cur<<1);if(qr>mid)res+=qry(ql,qr,mid+1,r,cur<<1|1);update(cur);return res;
}
inline void build(const int &l=1,const int &r=n,const int &cur=1)
{
	if(l==r)return Sm[cur]=Tm[l],Sq[cur]=Tm[l]*Tm[l],void();const int &mid=(l+r)>>1;
	build(l,mid,cur<<1);build(mid+1,r,cur<<1|1);update(cur);
}
inline int Qry(const int &ql,const int &qr,const int &l=1,const int &r=n,const int &cur=1)
{
//	if(cur==1)printf("Qry %d %d :: ",ql,qr);
	if(ql<=l&&r<=qr)return Sm[cur];pushdown(cur,l,r);const int &mid=(l+r)>>1;int res=0;
	if(ql<=mid)res=Qry(ql,qr,l,mid,cur<<1);if(qr>mid)res+=Qry(ql,qr,mid+1,r,cur<<1|1);update(cur);
//	if(cur==1)printf("%d\n",res);
	return res;
}
//
inline void Add(int x,const int &v){S1+=v;while(x)add(idx[top[x]],idx[x],v),x=fa[top[x]];}
inline int Qry(int x)
{
	LL ans=Sq[1]+S1*S1*dep[x],sm=0;//printf("#d : %d\n",Sq[1]);
	while(x)sm+=Qry(idx[top[x]],idx[x]),x=fa[top[x]];sm-=Qry(1,1);
	return ans-2*sm*S1;
//	LL ans=Sq[1]+dep[x]*qry(1,1);
//	printf("%lld\n",ans);while(x)ans-=2*S1*Qry(idx[top[x]],idx[x]),x=fa[top[x]];return ans;
}
signed main()
{
	n=read();int Q=read();rep(2,n,i)ins(read(),read());
	rep(1,n,i)S1+=V[i]=read();dep[0]=-1;dfs1();dfs2();rep(1,n,i)Tm[idx[i]]=S[i];build();
//	printf("S::");rep(1,n,i)printf("%d ",S[i]);puts("");
//	printf("V::");rep(1,n,i)printf("%d ",V[i]);puts("");
//	printf("idx::");rep(1,n,i)printf("%d ",idx[i]);puts("");
//	printf("Sq::");rep(1,n,i)printf("%d ",qry(i,i));puts("");
	int x,v;while(Q--)switch(read())
	{
		case 1:	{x=read();v=read();Add(x,v-V[x]);V[x]=v;break;}
		case 2:	{printf("%lld\n",Qry(read()));break;}
	}
}
